import { moduleMetadata } from '@storybook/angular';
import { PfTagComponent } from './tag.component';
const meta = {
    title: 'Composants/Tag',
    component: PfTagComponent,
    tags: ['autodocs'],
    parameters: {
        docs: {
            description: {
                component: "Badge de statut, catégorie ou filtre actif. 5 variantes sémantiques. Optionnellement supprimable.",
            },
        },
    },
    decorators: [moduleMetadata({ imports: [PfTagComponent] })],
    argTypes: {
        variant: { control: 'select', options: ['neutral', 'info', 'success', 'warning', 'danger'] },
        removable: { control: 'boolean' },
    },
    args: { variant: 'neutral' },
    render: (args) => ({
        props: args,
        template: `<pf-tag [variant]="variant" [removable]="removable || false">En cours</pf-tag>`,
    }),
};
export default meta;
export const Default = {};
export const Variants = {
    render: () => ({
        template: `
      <div style="display: flex; gap: 8px; flex-wrap: wrap;">
        <pf-tag variant="neutral">Brouillon</pf-tag>
        <pf-tag variant="info">En cours</pf-tag>
        <pf-tag variant="success">Validé</pf-tag>
        <pf-tag variant="warning">À compléter</pf-tag>
        <pf-tag variant="danger">Refusé</pf-tag>
      </div>
    `,
    }),
};
export const Removable = {
    args: { removable: true },
};
